SELECT *
FROM job_posting
WHERE enterprise_id = #{enterpriseId}

    AND status = #{status}


    AND job_type = #{jobType}


    AND (
        job_title LIKE CONCAT('%', #{keyword}, '%')
        OR job_category LIKE CONCAT('%', #{keyword}, '%')
        OR work_location LIKE CONCAT('%', #{keyword}, '%')
    )

ORDER BY updated_time DESC, id DESC

SELECT *
FROM job_posting
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
LIMIT 1

mapper.update:
UPDATE job_posting
SET status = #{status},
    publish_time = CASE
        WHEN #{publishTime} IS NULL THEN publish_time
        ELSE #{publishTime}
    END,
    updated_time = #{updatedTime}
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

mapper.delete:
DELETE
FROM job_posting
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
